[{'name': '사무실재실제어', 'cron': '', 'period': 100, 'code': 'triggered := false
absenceTimer := 0
presence = any(#OccupancySensor).presence
if (presence == "present") {
    if (triggered == false) {
        all(#SmartPlug).on()
        all(#Switch).on()
        all(#Light).on()
        triggered = true
        absenceTimer = 0
    } else {
        absenceTimer = 0
    }
} else {
    absenceTimer = absenceTimer + 100
    if (absenceTimer >= 900000) {
        all(#Switch).off()
        triggered = false
        absenceTimer = 0
    }
}'}]

[{'name': '회의실에어컨목표온도교대', 'cron': '', 'period': 3600000, 'code': 'toggle := false
if (toggle == false) {
  (#AirConditioner #회의실).airConditionerMode_setTemperature(25)
  toggle = true
} else {
  (#AirConditioner #회의실).airConditionerMode_setTemperature(20)
  toggle = false
}'}]

