[{'name': 'WineCellarTempChangeAlert', 'cron': '', 'period': 600000, 'code': 'previous_temp := (#TemperatureSensor).temperatureMeasurement_temperature
wait until ((#TemperatureSensor).temperatureMeasurement_temperature != previous_temp)
if (abs(((#TemperatureSensor).temperatureMeasurement_temperature - previous_temp)) >= 1) {
  (#Speaker).mediaPlayback_speak("와인 셀러의 온도가 급변했습니다")
}
previous_temp := (#TemperatureSensor).temperatureMeasurement_temperature'}]

[{'name': 'HighCO2Warning', 'cron': '', 'period': -1, 'code': 'if ((#AirQualityDetector).co2Measurement_co2 >= 1200 and (#OccupancySensor).presenceSensor_presence == "present") {
  (#AirPurifier).airPurifierFanMode_setAirPurifierFanMode("high")
  (#Speaker).mediaPlayback_speak("주의! 이산화탄소 농도가 높습니다. 공기청정기를 강풍으로 변경하였습니다.")
}'}]

[{'name': 'OvenModeChange', 'cron': '', 'period': -1, 'code': 'if ((#Oven).ovenMode_ovenMode == "heating" and (#OccupancySensor).presenceSensor_presence == "not present") {
  (#Oven).ovenMode_setOvenMode("warm")
  (#Speaker).mediaPlayback_speak("Oven changed to warm mode")
}'}]

[{'name': 'PumpToggle', 'cron': '', 'period': 5000, 'code': 'triggered := false
if ((#Pump).switch_switch == "off") {
  (#Pump).switch_on()
  triggered = true
} else if ((#Pump).switch_switch == "on") {
  (#Pump).switch_off()
  triggered = false
}'}]

[{'name': 'ToggleVacuumMode', 'cron': '', 'period': 1800000, 'code': 'mode := false
if (mode == false) {
  (#VacuumCleaner).vacuumMode_setVacuumMode("sleep")
  mode = true
} else {
  (#VacuumCleaner).vacuumMode_setVacuumMode("auto")
  mode = false
}'}]

[{'name': 'ToggleAirPurifierModes', 'cron': '', 'period': 1800000, 'code': 'mode := false
if (mode == false) {
  (#AirPurifier).airPurifierFanMode_setAirPurifierFanMode("sleep")
  mode = true
} else {
  (#AirPurifier).airPurifierFanMode_setAirPurifierFanMode("high")
  mode = false
}'}]

[{'name': 'DoorOpenAnnouncement', 'cron': '', 'period': 60000, 'code': 'triggered := false
if ((#DoorLock).doorControl_door == "open") {
  if (triggered == false) {
    (#Speaker).mediaPlayback_speak("어서오세요")
    triggered = true
  }
} else {
  triggered = false
}'}]

[{'name': 'CheckSafeBox', 'cron': '', 'period': 300000, 'code': 'triggered := false
if ((#Door).doorControl_door == "open") {
  wait until ((#SafeBox).safeBox_lockStatus == "locked")
  triggered = true
}
if (triggered) {
  (#Speaker).mediaPlayback_speak("금고가 열려있습니다")
}'}]

[{'name': 'LeakDetectedAlert', 'cron': '', 'period': 60000, 'code': 'if ((#LeakSensor).leakSensor_leakage == "detected") {
  (#Valve).valve_close()
  (#Speaker).mediaPlayback_speak("누수가 감지되었습니다. 대피하세요")
  triggered := true
} else {
  triggered := false
}'}]

[{'name': 'FireAlertAndEmail', 'cron': '', 'period': 300000, 'code': 'triggered := false
if ((#SmokeDetector).smokeDetector_smoke == "detected") {
  if (triggered == false) {
    (#Speaker).mediaPlayback_speak("화재를 알리는 소리를 들으세요.")
    (#EmailProvider).emailProvider_sendMail("test@example.com", "화재 경고", "화재가 발생했습니다. 대피하세요")
    triggered = true
  }
} else {
  triggered = false
}'}]

[{'name': 'TopLightTriggerBottomLight', 'cron': '', 'period': 100, 'code': 'topLightStatus := false
if ((#Light_Top).switch_switch == "on") {
  if (topLightStatus == false) {
    (#Light_Bottom).switch_on()
    topLightStatus = true
  }
} else {
  topLightStatus = false
}'}]

[{'name': 'AutoModeForEvenTaggedRobots', 'cron': '', 'period': 100, 'code': 'if ((#Button).button_button == "pushed") {
  robots = all(#RobotCleaner)
  for (robot in robots) {
    if (robot.tags.includes("even")) {
      robot.robotCleanerCleaningMode_setRobotCleanerCleaningMode("auto")
    }
  }
}'}]

[{'name': 'EntranceMotionLight', 'cron': '', 'period': 100, 'code': 'motionDetected := false
if (motionDetected == false) {
  wait until ((#MotionSensor).motionSensor_motion == "active")
  (#Light).switchLevel_setLevel(100)
  motionDetected = true
} else {
  wait until (#Clock).clock_delay(3000)
  (#Light).switch_off()
  motionDetected = false
}'}]

[{'name': 'CO2LevelAlert', 'cron': '', 'period': 10000, 'code': 'co2High := false
if ((#Garage).gasMeter_gasMeter > 880) {
  if (co2High == false) {
    (#GarageSpeaker).mediaPlayback_speak("CO2 농도 위험")
    co2High = true
  }
} else {
  co2High = false
}'}]

[{'name': 'FireAlarmAndAnnouncement', 'cron': '', 'period': 10000, 'code': 'triggered := false
if ((#SmokeDetector).smokeDetector_smoke == "detected") {
  if (triggered == false) {
    all(#Alarm).alarm_siren()
    (#Speaker).mediaPlayback_speak("대피하세요")
    triggered = true
  }
} else {
  triggered = false
}'}]

[{'name': 'EmergencySirenAlert', 'cron': '', 'period': 60000, 'code': 'triggered := false
if (triggered == false) {
  wait until (any(#Floor1_PresenceSensor).presenceSensor_presence == "present")
  (#EmergencySiren).sirenMode_setSirenMode("siren")
  (#Clock).clock_delay(3000)
  (#EmergencySiren).sirenMode_setSirenMode("off")
  triggered = true
} else {
  break
}'}]

